#[cfg(feature = "heuristics")]
pub struct UserChunkConfig(pub xberg::UserChunkConfig);
#[cfg(feature = "heuristics")]
impl UserChunkConfig {
    pub fn new(
        page_ranges: Option<Vec<PageRange>>,
        pages_per_chunk: Option<u32>,
        force_chunking: bool,
        disable_chunking: bool,
    ) -> UserChunkConfig {
        let mut __target: xberg::UserChunkConfig = ::std::default::Default::default();
        if let Some(v) = page_ranges {
            __target.page_ranges = Some(v.into_iter().map(|w| w.0).collect());
        }
        __target.pages_per_chunk = pages_per_chunk;
        __target.force_chunking = force_chunking;
        __target.disable_chunking = disable_chunking;
        UserChunkConfig(__target)
    }
    pub fn page_ranges(&self) -> String {
        serde_json::to_string(&self.0.page_ranges.as_ref().map(|v| {
            v.iter()
                .map(|elem| serde_json::to_string(elem).unwrap_or_else(|_| "null".to_string()))
                .collect::<Vec<_>>()
        }))
        .expect("serializable enum vec")
    }
    pub fn pages_per_chunk(&self) -> Option<u32> {
        self.0.pages_per_chunk.as_ref().and_then(|v| {
            ::serde_json::to_value(v)
                .ok()
                .and_then(|j| ::serde_json::from_value(j).ok())
        })
    }
    pub fn force_chunking(&self) -> bool {
        ::serde_json::to_value(&self.0.force_chunking)
            .ok()
            .and_then(|j| ::serde_json::from_value(j).ok())
            .unwrap_or_default()
    }
    pub fn disable_chunking(&self) -> bool {
        ::serde_json::to_value(&self.0.disable_chunking)
            .ok()
            .and_then(|j| ::serde_json::from_value(j).ok())
            .unwrap_or_default()
    }
}

